// Helpers
function formatDate(dateInput) {
  if (!dateInput) {
    const today = new Date();
    const year = today.getFullYear();
    const month = String(today.getMonth() + 1).padStart(2, '0');
    const day = String(today.getDate()).padStart(2, '0');
    return `${day}-${month}-${year}`;
  }
  const d = new Date(dateInput);
  const day = String(d.getDate()).padStart(2, '0');
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const year = d.getFullYear();
  return `${day}-${month}-${year}`;
}
function safeText(value) {
  if (value == null) return '';
  return String(value).replace(/\s+/g, ' ').trim();
}

// Convierte HTML simple (p, ul, ol, li, br) en Paragraphs compatibles con docx
function parseHtmlToParagraphs(html = '') {
  const paragraphs = [];
  if (!html) {
    paragraphs.push(new Paragraph({
      text: ''
    }));
    return paragraphs;
  }
  try {
    const parser = new DOMParser();
    const doc = parser.parseFromString(`<div>${html}</div>`, 'text/html');
    const root = doc.body.firstElementChild || doc.body;
    root.childNodes.forEach(node => {
      if (node.nodeType !== Node.ELEMENT_NODE) return;
      const tag = node.tagName.toLowerCase();
      if (tag === 'p') {
        const text = safeText(node.textContent);
        if (text) {
          paragraphs.push(new Paragraph({
            children: [new TextRun(text)],
            spacing: {
              after: 120
            }
          }));
        }
      } else if (tag === 'ul' || tag === 'ol') {
        const isOrdered = tag === 'ol';
        const isLetter = node.getAttribute && /data-type\s*=\s*["']letter["']/i.test(node.outerHTML);
        node.querySelectorAll('li').forEach(li => {
          const liText = safeText(li.textContent);
          if (!liText) return;
          paragraphs.push(new Paragraph({
            children: [new TextRun(liText)],
            bullet: isOrdered ? undefined : {
              level: 0
            },
            numbering: isOrdered ? {
              reference: "default-numbering",
              level: 0
            } : undefined,
            spacing: {
              after: 80
            }
          }));
        });
      } else {
        // otros tags: tratar su texto como párrafo
        const text = safeText(node.textContent);
        if (text) {
          paragraphs.push(new Paragraph({
            children: [new TextRun(text)],
            spacing: {
              after: 120
            }
          }));
        }
      }
    });
  } catch (e) {
    // Fallback simple: quitar tags y devolver como párrafos por saltos de línea
    const cleaned = String(html).replace(/<br\s*\/?>/gi, '\n').replace(/<[^>]+>/g, '').replace(/&nbsp;/g, ' ').trim();
    cleaned.split(/\n+/).map(s => safeText(s)).filter(Boolean).forEach(t => {
      paragraphs.push(new Paragraph({
        children: [new TextRun(t)],
        spacing: {
          after: 120
        }
      }));
    });
  }

  // Si no hay contenido, agregar párrafo vacío
  if (paragraphs.length === 0) {
    paragraphs.push(new Paragraph({
      text: ''
    }));
  }
  return paragraphs;
}
