        shadingColor = "E3F2FD"; // Azul claro
        break;
      case 'question':
        shadingColor = "FFF3CD"; // Amarillo claro
        break;
      case 'alternative':
        shadingColor = "D1ECF1"; // Celeste claro
        break;
      case 'end':
        shadingColor = "D4EDDA"; // Verde más claro
        break;
    }
    const shading = shadingColor ? {
      fill: shadingColor,
      type: ShadingType.CLEAR
    } : undefined;
    const indent = level === 'sub' ? {
      left: 200
    } : undefined;
    rows.push(new TableRow({
      children: [new TableCell({
        shading: shading,
        children: [new Paragraph({
          children: [new TextRun(number)],
          spacing: {
            before: 0,
